#pragma once

#include <memory>
#include <string>

#include "envoy/http/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThroughFilter {

/**
 * Configuration for the pass through filter.
 */
class PassThroughFilterConfig {
public:
  PassThroughFilterConfig() = default;
};

using PassThroughFilterConfigSharedPtr = std::shared_ptr<PassThroughFilterConfig>;

/**
 * A minimal filter that passes all request data through with Continue status.
 * This filter implements Http::StreamDecoderFilter and demonstrates the
 * basic extension pattern used in Envoy HTTP filters.
 */
class PassThroughFilter : public Http::StreamDecoderFilter {
public:
  PassThroughFilter(PassThroughFilterConfigSharedPtr config);

  // Http::StreamFilterBase
  void onDestroy() override {}

  // Http::StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
                                          bool end_stream) override;
  Http::FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override;
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;

private:
  PassThroughFilterConfigSharedPtr config_;
  Http::StreamDecoderFilterCallbacks* callbacks_{};
};

} // namespace PassThroughFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "pass_through_filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThroughFilter {

PassThroughFilter::PassThroughFilter(PassThroughFilterConfigSharedPtr config)
    : config_(config) {}

Http::FilterHeadersStatus PassThroughFilter::decodeHeaders(Http::RequestHeaderMap& headers,
                                                           bool end_stream) {
  // Simply pass through all request headers
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterDataStatus PassThroughFilter::decodeData(Buffer::Instance& data, bool end_stream) {
  // Simply pass through all request data
  return Http::FilterDataStatus::Continue;
}

Http::FilterTrailersStatus PassThroughFilter::decodeTrailers(Http::RequestTrailerMap& trailers) {
  // Simply pass through all request trailers
  return Http::FilterTrailersStatus::Continue;
}

void PassThroughFilter::setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) {
  callbacks_ = &callbacks;
}

} // namespace PassThroughFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#pragma once

#include "envoy/http/filter_factory.h"
#include "envoy/server/filter_config.h"

#include "pass_through_filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThroughFilter {

/**
 * Config registration for the pass through filter.
 * Implements NamedHttpFilterConfigFactory pattern for filter registration.
 */
class PassThroughFilterFactory : public Server::Configuration::NamedHttpFilterConfigFactory {
public:
  absl::StatusOr<Http::FilterFactoryCb> createFilterFactoryFromProto(
      const Protobuf::Message& proto_config, const std::string& stats_prefix,
      Server::Configuration::FactoryContext& context) override;

  ProtobufTypes::MessagePtr createEmptyConfigProto() override {
    return std::make_unique<Envoy::ProtobufWkt::Empty>();
  }

  std::string name() const override { return "envoy.filters.http.pass_through"; }

  bool isTerminalFilterByProto(const Protobuf::Message&,
                               Server::Configuration::ServerFactoryContext&) override {
    return false;
  }
};

DECLARE_FACTORY(PassThroughFilterFactory);

} // namespace PassThroughFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "pass_through_filter_config.h"

#include "envoy/registry/registry.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThroughFilter {

absl::StatusOr<Http::FilterFactoryCb> PassThroughFilterFactory::createFilterFactoryFromProto(
    const Protobuf::Message&, const std::string&, Server::Configuration::FactoryContext&) {
  PassThroughFilterConfigSharedPtr filter_config(new PassThroughFilterConfig());
  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamDecoderFilter(std::make_shared<PassThroughFilter>(filter_config));
  };
}

/**
 * Static registration for the pass through filter.
 * This registers the filter factory with Envoy's filter registry,
 * making it available for use in Envoy configurations.
 */
REGISTER_FACTORY(PassThroughFilterFactory, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace PassThroughFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

